SELECT TOP 1 [CHANNEL], SUM(NS.[DAILY_SENT]) AS WEEKLY_SENT,
	SUM(NS.[DAILY_DELIVERED]) AS WEEKLY_DELIVERED 
FROM [NOTIFICATION_STATISTICS] NS 
WHERE NS.[IsDeleted] = 0 
	AND NS.[STATISTICS_DATE] > DATEADD(DAY, -7,
	GETDATE()) 
GROUP BY NS.[CHANNEL] 
ORDER BY NS.[CHANNEL] 